var e=[{id:`L4_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`큭!!`,JPN:`くっ！！`,ENG:`Ngh!`,TWN:`唔！！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`뭐야, 그 검?`,JPN:`何よ、その剣は！！`,ENG:`That sword!`,TWN:`什麼，那把劍？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`예전에는 아주 잠깐밖에 사용하지 못했던 것 같은데......`,JPN:`以前は、短時間しか使えてなかったのに……`,ENG:`You couldn't wield it for very long last time.`,TWN:`以前應該只能用一下下的……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`......설마 그 사이에 무슨 파워 업이라도 한 거야?`,JPN:`……まさか、何かパワーアップでもしたの？`,ENG:`Did something happen since then?`,TWN:`……該不會在這段時間增強了什麼力量吧？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`그렇다고 해 두지!!`,JPN:`そういうこと！！`,ENG:`Does it matter?`,TWN:`就當是那樣吧！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`크윽!`,JPN:`くうっ！`,ENG:`Hngh!`,TWN:`唔呃！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`동료들을 버리고 테러리스트와 한 편이 되면서까지 강해졌다는 게......`,JPN:`仲間を見捨てて、テロリストとぐるになってまで手に入れた力は……`,ENG:`Wasn't it for power that you abandoned your comrades and decided to work with the terrorists?`,TWN:`妳拋棄夥伴，不惜和恐怖分子為伍也要變強……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`고작 이 정도야? 서윤!`,JPN:`たかがこの程度なの？　アオイ・シズカ！`,ENG:`I'm disappointed, Seo Yoon?`,TWN:`就只有這種程度嗎？徐芸！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`하아...... 하아......`,JPN:`はあ……はあ……`,ENG:`Huff... Huff...`,TWN:`哈啊……哈啊……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`알고는 있었지만......`,JPN:`気づいてはいたけど……`,ENG:`It's not like I didn't know it...`,TWN:`雖然早就知道了……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`역시 강하네...... 유미나.`,JPN:`やっぱり強いな……ヤナギ・ミナ。`,ENG:`But you're strong, Yoo Mina.`,TWN:`妳果然很強呢……劉米娜。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`원래도 강했는데 그 사이에 더 성장하다니......`,JPN:`元々強かったのに、もっと成長するなんて……`,ENG:`You grew even stronger, and you were already a handful before.`,TWN:`本來實力就很強了，這段時間又成長了不少……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`이래서 널 좋아할 수가 없다니까.`,JPN:`これだから、あなたのこと好きになれないのよ。`,ENG:`This is why I can never get myself to like you.`,TWN:`就是因為這樣，我才沒辦法喜歡妳。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`하지만 말이지......`,JPN:`でもね……`,ENG:`But...`,TWN:`不過啊……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_LAUGH`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`너도 꽤 한계이지 않아?`,JPN:`あなたもかなり限界じゃない？`,ENG:`You're also pretty exhausted, huh?`,TWN:`妳也到極限了，對吧？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SEOYOON_REPLACER_NULL_LANCE`,text:{KOREA:`그 검...... 몇 번이나 더 휘두를 수 있을까?`,JPN:`その剣……あと何回振り回せるかな？`,ENG:`That sword... How much more do you think you could swing it?`,TWN:`那把劍……妳還能揮動幾次呢？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SEOYOON_REPLACER_NULL_LANCE`,face:`UNIT_IDLE`},R:null}}}];export{e as default};